CREATE TABLE `CommunityInstallation` (`id` VARCHAR(191) NOT NULL, `accountId` VARCHAR(191) NOT NULL, `packageId` VARCHAR(191) NOT NULL, `releaseId` VARCHAR(191) NOT NULL, `operationId` VARCHAR(191) NOT NULL, `mode` VARCHAR(191) NOT NULL, `installedPackageChecksum` VARCHAR(191) NOT NULL, `localModificationChecksum` VARCHAR(191) NULL, `upstreamReleaseId` VARCHAR(191) NULL, `installedAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), `updatedAt` DATETIME(3) NOT NULL, PRIMARY KEY (`id`), UNIQUE INDEX `CommunityInstallation_operationId_key` (`operationId`), INDEX `CommunityInstallation_accountId_upstreamReleaseId_idx` (`accountId`,`upstreamReleaseId`), CONSTRAINT `CommunityInstallation_operationId_fkey` FOREIGN KEY (`operationId`) REFERENCES `CommunityInstallOperation`(`id`) ON DELETE RESTRICT ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `CommunityRemixLineage` (`id` VARCHAR(191) NOT NULL, `derivedReleaseId` VARCHAR(191) NOT NULL, `sourceReleaseId` VARCHAR(191) NOT NULL, `rootReleaseId` VARCHAR(191) NOT NULL, `sourcePackageChecksum` VARCHAR(191) NOT NULL, `mode` VARCHAR(191) NOT NULL, `attributionSnapshot` LONGTEXT NOT NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `CommunityRemixLineage_derivedReleaseId_key` (`derivedReleaseId`), INDEX `CommunityRemixLineage_sourceReleaseId_idx` (`sourceReleaseId`), INDEX `CommunityRemixLineage_rootReleaseId_idx` (`rootReleaseId`)) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE TABLE `CommunityReleaseUpdate` (`id` VARCHAR(191) NOT NULL, `installationId` VARCHAR(191) NOT NULL, `currentReleaseId` VARCHAR(191) NOT NULL, `candidateReleaseId` VARCHAR(191) NOT NULL, `comparison` LONGTEXT NOT NULL, `localEditProtected` BOOLEAN NOT NULL DEFAULT false, `resolvedAt` DATETIME(3) NULL, `createdAt` DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3), PRIMARY KEY (`id`), UNIQUE INDEX `CommunityReleaseUpdate_installationId_candidateReleaseId_key` (`installationId`,`candidateReleaseId`), INDEX `CommunityReleaseUpdate_installationId_resolvedAt_idx` (`installationId`,`resolvedAt`), CONSTRAINT `CommunityReleaseUpdate_installationId_fkey` FOREIGN KEY (`installationId`) REFERENCES `CommunityInstallation`(`id`) ON DELETE CASCADE ON UPDATE CASCADE) DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
